    #[test]
    fn abs_bf16x2_uses_only_canonical_or_compatibility_defpaths() {
        assert!(is_generated_intrinsic_path(
            "cuda_intrinsics::__cuda_oxide_intrinsic_abi_v1::i0070"
        ));
        assert!(is_raw_generated_intrinsic_path(
            "cuda_intrinsics::__cuda_oxide_intrinsic_abi_v1::i0070"
        ));
        assert_eq!(
            generated_intrinsic_marker("cuda_intrinsics::__cuda_oxide_intrinsic_abi_v1::i0070"),
            Some("v1:i0070")
        );
        assert!(matches!(
            classify_raw_intrinsic_path(
                "cuda_intrinsics",
                "cuda_intrinsics::__cuda_oxide_intrinsic_abi_v1::i0070".into()
            ),
            RawIntrinsicIdentity::Known(_)
        ));
        assert!(!is_generated_intrinsic_path(
            "cuda_intrinsics::bf16x2::abs_bf16x2"
        ));
        assert!(is_generated_intrinsic_path(
            "cuda_device::bf16x2::abs_bf16x2"
        ));
        assert!(!is_raw_generated_intrinsic_path(
            "cuda_device::bf16x2::abs_bf16x2"
        ));
        assert_eq!(
            generated_intrinsic_marker("cuda_device::bf16x2::abs_bf16x2"),
            Some("v1:i0070")
        );
        assert!(!is_generated_intrinsic_path(
            "cuda_intrinsics::__cuda_oxide_intrinsic_abi_v2::i0070"
        ));
    }
